6653 /// Given a min/max intrinsic, see if it can be removed based on having an
6654 /// operand that is another min/max intrinsic with shared operand(s). The caller
6655 /// is expected to swap the operand arguments to handle commutation.
6656 static Value *foldMinimumMaximumSharedOp(Intrinsic::ID IID, Value *Op0,
6657                                          Value *Op1) {
6658   auto IsMinimumMaximumIntrinsic = [](Intrinsic::ID ID) {
6659     switch (ID) {
6660     case Intrinsic::maxnum:
6661     case Intrinsic::minnum:
6662     case Intrinsic::maximum:
6663     case Intrinsic::minimum:
6664     case Intrinsic::maximumnum:
6665     case Intrinsic::minimumnum:
6666       return true;
6667     default:
6668       return false;
6669     }
6670   };
6671 
6672   assert(IsMinimumMaximumIntrinsic(IID) && "Unsupported intrinsic");
6673 
6674   auto *M0 = dyn_cast<IntrinsicInst>(Op0);
6675   // If Op0 is not the same intrinsic as IID, do not process.
6676   // This is a difference with integer min/max handling. We do not process the
6677   // case like max(min(X,Y),min(X,Y)) => min(X,Y). But it can be handled by GVN.
6678   if (!M0 || M0->getIntrinsicID() != IID)
6679     return nullptr;
6680   Value *X0 = M0->getOperand(0);
6681   Value *Y0 = M0->getOperand(1);
6682   // Simple case, m(m(X,Y), X) => m(X, Y)
6683   //              m(m(X,Y), Y) => m(X, Y)
6684   // For minimum/maximum, X is NaN => m(NaN, Y) == NaN and m(NaN, NaN) == NaN.
6685   // For minimum/maximum, Y is NaN => m(X, NaN) == NaN  and m(NaN, NaN) == NaN.
6686   // For minnum/maxnum, X is NaN => m(NaN, Y) == Y and m(Y, Y) == Y.
6687   // For minnum/maxnum, Y is NaN => m(X, NaN) == X and m(X, NaN) == X.
6688   if (X0 == Op1 || Y0 == Op1)
6689     return M0;
6690 
6691   auto *M1 = dyn_cast<IntrinsicInst>(Op1);
6692   if (!M1 || !IsMinimumMaximumIntrinsic(M1->getIntrinsicID()))
6693     return nullptr;
6694   Value *X1 = M1->getOperand(0);
6695   Value *Y1 = M1->getOperand(1);
6696   Intrinsic::ID IID1 = M1->getIntrinsicID();
6697   // we have a case m(m(X,Y),m'(X,Y)) taking into account m' is commutative.
6698   // if m' is m or inversion of m => m(m(X,Y),m'(X,Y)) == m(X,Y).
6699   // For minimum/maximum, X is NaN => m(NaN,Y) == m'(NaN, Y) == NaN.
6700   // For minimum/maximum, Y is NaN => m(X,NaN) == m'(X, NaN) == NaN.
6701   // For minnum/maxnum, X is NaN => m(NaN,Y) == m'(NaN, Y) == Y.
6702   // For minnum/maxnum, Y is NaN => m(X,NaN) == m'(X, NaN) == X.
6703   if ((X0 == X1 && Y0 == Y1) || (X0 == Y1 && Y0 == X1))
6704     if (IID1 == IID || getInverseMinMaxIntrinsic(IID1) == IID)
6705       return M0;
6706 
6707   return nullptr;
6708 }
