6710 enum class MinMaxOptResult {
6711   CannotOptimize = 0,
6712   UseNewConstVal = 1,
6713   UseOtherVal = 2,
6714   // For undef/poison, we can choose to either propgate undef/poison or
6715   // use the LHS value depending on what will allow more optimization.
6716   UseEither = 3
6717 };
6718 // Get the optimized value for a min/max instruction with a single constant
6719 // input (either undef or scalar constantFP). The result may indicate to
6720 // use the non-const LHS value, use a new constant value instead (with NaNs
6721 // quieted), or to choose either option in the case of undef/poison.
6722 static MinMaxOptResult OptimizeConstMinMax(const Constant *RHSConst,
6723                                            const Intrinsic::ID IID,
6724                                            const CallBase *Call,
6725                                            Constant **OutNewConstVal) {
6726   assert(OutNewConstVal != nullptr);
6727 
6728   bool PropagateNaN = IID == Intrinsic::minimum || IID == Intrinsic::maximum;
6729   bool ReturnsOtherForAllNaNs =
6730       IID == Intrinsic::minimumnum || IID == Intrinsic::maximumnum;
6731   bool IsMin = IID == Intrinsic::minimum || IID == Intrinsic::minnum ||
6732                IID == Intrinsic::minimumnum;
6733 
6734   // min/max(x, poison) -> either x or poison
6735   if (isa<UndefValue>(RHSConst)) {
6736     *OutNewConstVal = const_cast<Constant *>(RHSConst);
6737     return MinMaxOptResult::UseEither;
6738   }
6739 
6740   const ConstantFP *CFP = dyn_cast<ConstantFP>(RHSConst);
6741   if (!CFP)
6742     return MinMaxOptResult::CannotOptimize;
6743   APFloat CAPF = CFP->getValueAPF();
6744 
6745   // minnum(x, qnan) -> x
6746   // maxnum(x, qnan) -> x
6747   // minimum(X, nan) -> qnan
6748   // maximum(X, nan) -> qnan
6749   // minimumnum(X, nan) -> x
6750   // maximumnum(X, nan) -> x
6751   if (CAPF.isNaN()) {
6752     if (PropagateNaN) {
6753       *OutNewConstVal = ConstantFP::get(CFP->getType(), CAPF.makeQuiet());
6754       return MinMaxOptResult::UseNewConstVal;
6755     } else if (ReturnsOtherForAllNaNs || !CAPF.isSignaling()) {
6756       return MinMaxOptResult::UseOtherVal;
6757     }
6758     return MinMaxOptResult::CannotOptimize;
6759   }
6760 
6761   if (CAPF.isInfinity() || (Call && Call->hasNoInfs() && CAPF.isLargest())) {
6762     // minimum(X, -inf) -> -inf if nnan
6763     // maximum(X, +inf) -> +inf if nnan
6764     // minimumnum(X, -inf) -> -inf
6765     // maximumnum(X, +inf) -> +inf
6766     if (CAPF.isNegative() == IsMin &&
6767         (ReturnsOtherForAllNaNs || (Call && Call->hasNoNaNs()))) {
6768       *OutNewConstVal = const_cast<Constant *>(RHSConst);
6769       return MinMaxOptResult::UseNewConstVal;
6770     }
6771 
6772     // minnum(X, +inf) -> X if nnan
6773     // maxnum(X, -inf) -> X if nnan
6774     // minimum(X, +inf) -> X (ignoring quieting of sNaNs)
6775     // maximum(X, -inf) -> X (ignoring quieting of sNaNs)
6776     // minimumnum(X, +inf) -> X if nnan
6777     // maximumnum(X, -inf) -> X if nnan
6778     if (CAPF.isNegative() != IsMin &&
6779         (PropagateNaN || (Call && Call->hasNoNaNs())))
6780       return MinMaxOptResult::UseOtherVal;
6781   }
6782   return MinMaxOptResult::CannotOptimize;
6783 }
