6674   auto *M0 = dyn_cast<IntrinsicInst>(Op0);
6675   // If Op0 is not the same intrinsic as IID, do not process.
6676   // This is a difference with integer min/max handling. We do not process the
6677   // case like max(min(X,Y),min(X,Y)) => min(X,Y). But it can be handled by GVN.
6678   if (!M0 || M0->getIntrinsicID() != IID)
6679     return nullptr;
6680   Value *X0 = M0->getOperand(0);
6681   Value *Y0 = M0->getOperand(1);
6682   // Simple case, m(m(X,Y), X) => m(X, Y)
6683   //              m(m(X,Y), Y) => m(X, Y)
6684   // For minimum/maximum, X is NaN => m(NaN, Y) == NaN and m(NaN, NaN) == NaN.
6685   // For minimum/maximum, Y is NaN => m(X, NaN) == NaN  and m(NaN, NaN) == NaN.
6686   // For minnum/maxnum, X is NaN => m(NaN, Y) == Y and m(Y, Y) == Y.
6687   // For minnum/maxnum, Y is NaN => m(X, NaN) == X and m(X, NaN) == X.
6688   if (X0 == Op1 || Y0 == Op1)
